export const INSTANCE_STRIDE_BYTES = 16
export const INSTANCE_STRIDE_F32 = 4

export const FIELD_OFFSET_F32 = {
  position: 0,
  y: 1,
  length: 2,
  frequency: 3,
} as const

export const GL_ATTRIBUTES: readonly GlAttributeLayout[] = [
  { name: 'a_position', components: 1, type: 'uint', offsetBytes: 0, integer: true },
  { name: 'a_y', components: 1, type: 'uint', offsetBytes: 4, integer: true },
  { name: 'a_length', components: 1, type: 'uint', offsetBytes: 8, integer: true },
  { name: 'a_frequency', components: 1, type: 'float', offsetBytes: 12, integer: false },
]

export interface InstanceArrays {
  position: ArrayLike<number>
  y: ArrayLike<number>
  length: ArrayLike<number>
  frequency: ArrayLike<number>
}

export function packInstances(
  arrays: InstanceArrays,
  numInstances: number,
  buf: ArrayBuffer = new ArrayBuffer(numInstances * INSTANCE_STRIDE_BYTES),
) {
  const f32 = new Float32Array(buf)
  const u32 = new Uint32Array(buf)
  const { position, y, length, frequency } = arrays
  for (let i = 0; i < numInstances; i++) {
    const o = i * INSTANCE_STRIDE_F32
    u32[o + 0] = position[i]!
    u32[o + 1] = y[i]!
    u32[o + 2] = length[i]!
    f32[o + 3] = frequency[i]!
  }
  return buf
}
